css:
:root{
  --bg:#faf6f4;
  --panel:#ffffff;
  --panel-2:#fdf9fb;
  --line:rgba(120,90,140,.12);
  --line-soft:rgba(120,90,140,.09);
  --text:#4a4453;
  --ink:#352f40;
  --muted:#9a93a6;
  --rose:#e79ab4;
  --rose-deep:#c76f96;
  --lav:#b9a6e6;
  --mint:#a6ddc8;
  --peach:#f5c9a6;
  --sky:#a9d3ee;
  --accent:#c98bbb;
  --accent-deep:#a5618f;
  --maxw:1240px;
  --serif:'Fraunces',Georgia,serif;
  --sans:'DM Sans',system-ui,-apple-system,Segoe UI,Roboto,sans-serif;
  --ease:cubic-bezier(.22,.68,.24,1);
  --shadow:0 20px 50px -28px rgba(150,110,160,.5);
}
*{box-sizing:border-box}
html{scroll-behavior:smooth}
html,body{margin:0;padding:0}
body{
  background:var(--bg);
  color:var(--text);
  font-family:var(--sans);
  line-height:1.7;
  -webkit-font-smoothing:antialiased;
  overflow-x:hidden;
}
body::before{
  content:"";position:fixed;inset:0;z-index:-1;pointer-events:none;
  background:
    radial-gradient(760px 520px at 82% -6%, rgba(231,154,180,.22), transparent 60%),
    radial-gradient(680px 520px at -8% 4%, rgba(185,166,230,.20), transparent 60%),
    radial-gradient(720px 560px at 50% 116%, rgba(166,221,200,.20), transparent 62%),
    var(--bg);
}
a{color:inherit;text-decoration:none}
::selection{background:rgba(231,154,180,.32);color:var(--ink)}
.wrap{max-width:var(--maxw);margin:0 auto;padding:0 28px}

@keyframes rise{from{opacity:0;transform:translateY(22px)}to{opacity:1;transform:none}}
@keyframes fade{from{opacity:0}to{opacity:1}}

/* ---------- Nav ---------- */
.topnav{
  position:sticky;top:0;z-index:50;
  background:rgba(255,255,255,.66);
  backdrop-filter:blur(18px) saturate(150%);
  -webkit-backdrop-filter:blur(18px) saturate(150%);
  border-bottom:1px solid var(--line-soft);
}
.nav-inner{display:flex;align-items:center;gap:30px;height:74px}
.brand{
  font-family:var(--serif);font-weight:600;letter-spacing:.14em;
  font-size:23px;text-transform:uppercase;color:var(--ink);white-space:nowrap;
}
.brand span{
  color:var(--rose-deep);font-family:var(--sans);font-weight:600;
  letter-spacing:.14em;font-size:11px;margin-left:9px;
}
.brand.small{font-size:18px}
.nav-links{display:flex;gap:26px;margin-left:auto;flex-wrap:wrap}
.nav-links a{
  position:relative;color:var(--muted);font-size:12px;letter-spacing:.14em;
  text-transform:uppercase;font-weight:600;transition:color .25s var(--ease);padding:4px 0;
}
.nav-links a::after{
  content:"";position:absolute;left:0;right:100%;bottom:-2px;height:1.5px;border-radius:2px;
  background:linear-gradient(90deg,var(--rose),var(--lav));transition:right .3s var(--ease);
}
.nav-links a:hover{color:var(--accent-deep)}
.nav-links a:hover::after{right:0}
.admin-link{
  margin-left:10px;color:var(--accent-deep)!important;border:1px solid var(--line);
  padding:9px 18px;border-radius:999px;font-size:11px;text-transform:uppercase;letter-spacing:.12em;
  background:rgba(201,139,187,.08);transition:.25s var(--ease);
}
.admin-link:hover{background:rgba(201,139,187,.16);border-color:rgba(201,139,187,.4)}

/* ---------- Masthead ---------- */
.masthead{padding:84px 28px 26px;animation:rise .8s var(--ease) both}
.kicker{
  color:var(--rose-deep);text-transform:uppercase;letter-spacing:.36em;font-size:11px;font-weight:700;
  margin:0 0 20px;display:flex;align-items:center;gap:16px;
}
.kicker::before,.kicker::after{content:"";height:2px;width:42px;border-radius:2px;background:linear-gradient(90deg,transparent,var(--rose))}
.kicker::after{background:linear-gradient(90deg,var(--rose),transparent)}
.masthead h1{
  font-family:var(--serif);font-weight:600;font-size:clamp(42px,7vw,96px);line-height:1.02;margin:0;
  letter-spacing:-.01em;color:var(--ink);
}
.masthead h1{
  background:linear-gradient(100deg,#5a5068 0%,var(--accent-deep) 46%,var(--rose-deep) 100%);
  -webkit-background-clip:text;background-clip:text;color:transparent;
}

/* ---------- Hero ---------- */
.hero{display:grid;grid-template-columns:1.5fr 1fr;gap:24px;padding-bottom:26px}
.hero .card-big{animation:rise .9s var(--ease) both;min-height:0}
.hero .card-big .card-cover{aspect-ratio:16/10}
.hero .card-big h3{font-size:clamp(23px,2.5vw,33px);line-height:1.12}
.hero .card-big .excerpt{font-size:15.5px}

/* ---------- Section title ---------- */
.section-title{
  font-family:var(--serif);font-size:15px;font-weight:600;margin:54px 0 26px;
  text-transform:uppercase;letter-spacing:.2em;color:var(--ink);
  display:flex;align-items:center;gap:18px;
}
.section-title::after{content:"";flex:1;height:1.5px;border-radius:2px;background:linear-gradient(90deg,var(--line),transparent)}

/* ---------- Cards ---------- */
.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:26px;padding-bottom:38px}
.card{
  position:relative;background:var(--panel);
  border:1px solid var(--line-soft);border-radius:22px;overflow:hidden;
  display:flex;flex-direction:column;box-shadow:0 12px 34px -26px rgba(150,110,160,.45);
  transition:transform .45s var(--ease),box-shadow .45s var(--ease);
  animation:rise .7s var(--ease) both;
}
.grid .card:nth-child(2){animation-delay:.06s}
.grid .card:nth-child(3){animation-delay:.12s}
.grid .card:nth-child(4){animation-delay:.18s}
.grid .card:nth-child(5){animation-delay:.24s}
.grid .card:nth-child(6){animation-delay:.3s}
.card:hover{transform:translateY(-8px);box-shadow:0 34px 60px -30px rgba(150,110,160,.55)}
.card-cover{display:block;position:relative;aspect-ratio:16/10;background-size:cover;background-position:center;overflow:hidden}
.card-cover img{width:100%;height:100%;object-fit:cover;transition:transform 1s var(--ease)}
.card:hover .card-cover{}
.cat-chip{
  position:absolute;top:16px;left:16px;z-index:4;
  background:rgba(255,255,255,.82);backdrop-filter:blur(8px);
  color:var(--accent-deep);font-size:10.5px;letter-spacing:.14em;text-transform:uppercase;
  font-weight:700;padding:7px 14px;border-radius:999px;border:1px solid rgba(201,139,187,.28);
}
.cat-chip.dark{position:static;display:inline-block;margin-bottom:22px;background:rgba(201,139,187,.14)}
.card-body{padding:22px 24px 26px}
.card h3{font-family:var(--serif);font-size:22px;line-height:1.26;margin:0 0 11px;font-weight:600;color:var(--ink);letter-spacing:-.005em}
.card h3 a{background:linear-gradient(var(--rose),var(--rose)) 0 100%/0 1.5px no-repeat;transition:background-size .35s var(--ease),color .25s}
.card h3 a:hover{color:var(--rose-deep);background-size:100% 1.5px}
.excerpt{color:var(--muted);font-size:14.5px;margin:0 0 18px;line-height:1.65}
.meta{color:var(--accent-deep);font-size:11px;letter-spacing:.1em;text-transform:uppercase;font-weight:600}

/* ---------- Article ---------- */
.post{animation:fade .6s var(--ease) both}
.post-cover{
  position:relative;height:clamp(280px,50vh,500px);background-size:cover;background-position:center;
  border-radius:0 0 30px 30px;
}
.post-cover::after{content:"";position:absolute;inset:0;border-radius:0 0 30px 30px;background:linear-gradient(to top,rgba(250,246,244,.5),transparent 55%)}
.post-inner{max-width:740px;padding-top:44px;padding-bottom:34px;animation:rise .8s var(--ease) both}
.post-inner h1{font-family:var(--serif);font-size:clamp(32px,5vw,54px);line-height:1.08;margin:0 0 20px;font-weight:600;color:var(--ink);letter-spacing:-.01em}
.post-meta{color:var(--accent-deep);text-transform:uppercase;letter-spacing:.12em;font-size:12px;font-weight:600;margin-bottom:36px;padding-bottom:28px;border-bottom:1px solid var(--line)}
.post-body{font-size:18.5px;line-height:1.9;color:#5a5464}
.post-body p{margin:0 0 26px}
.post-body p:first-of-type{font-size:21px;color:var(--ink)}
.post-body p:first-of-type::first-letter{
  font-family:var(--serif);font-size:70px;line-height:.72;float:left;margin:10px 14px 0 0;font-weight:600;
  color:var(--rose-deep);
}
.back{
  display:inline-block;margin-top:26px;color:var(--accent-deep);font-size:13px;letter-spacing:.06em;text-transform:uppercase;font-weight:600;
  border:1px solid var(--line);padding:11px 20px;border-radius:999px;transition:.25s var(--ease)
}
.back:hover{background:rgba(201,139,187,.1);border-color:rgba(201,139,187,.4)}
.related{padding-bottom:70px;padding-top:30px}

.empty{color:var(--muted);padding:36px 0;font-size:15px}
.empty a,.post-body a{color:var(--rose-deep)}

/* ---------- Footer ---------- */
.site-footer{
  border-top:1px solid var(--line);margin-top:60px;padding:52px 0;
  background:linear-gradient(180deg,transparent,rgba(231,154,180,.06))
}
.site-footer .wrap{display:flex;align-items:center;gap:20px;flex-wrap:wrap}
.site-footer .brand.small{color:var(--ink)}
.site-footer p{color:var(--muted);font-size:13px;margin:0}

/* ---------- Admin ---------- */
body.admin{background:#f6f1f6}
.admin-nav{background:rgba(255,255,255,.72)}
.admin-main{padding:44px 28px 90px}
.admin-head{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:28px;gap:16px;flex-wrap:wrap}
.admin-head h1{font-family:var(--serif);font-size:38px;margin:0;color:var(--ink);font-weight:600}
.muted{color:var(--muted);font-size:13px;margin:4px 0 0}
.btn{
  background:linear-gradient(180deg,var(--rose),var(--rose-deep));color:#fff;border:none;border-radius:12px;
  padding:12px 20px;font-weight:600;font-size:14px;cursor:pointer;font-family:var(--sans);
  display:inline-block;box-shadow:0 10px 24px -12px rgba(199,111,150,.7);transition:filter .2s,transform .2s var(--ease)
}
.btn:hover{filter:brightness(1.04);transform:translateY(-1px)}
.btn.ghost{background:transparent;color:var(--accent-deep);border:1px solid var(--line);box-shadow:none}
.btn.small{padding:8px 13px;font-size:12.5px}
.btn.danger{background:transparent;color:#cc6f6f;border:1px solid rgba(204,111,111,.4);box-shadow:none}
.btn.danger:hover{background:rgba(204,111,111,.1)}
.admin-table{width:100%;border-collapse:collapse;background:var(--panel);border:1px solid var(--line-soft);border-radius:18px;overflow:hidden;box-shadow:var(--shadow)}
.admin-table th{text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.1em;color:var(--muted);padding:16px 20px;border-bottom:1px solid var(--line-soft)}
.admin-table td{padding:17px 20px;border-bottom:1px solid var(--line-soft);vertical-align:middle;font-size:14px;color:var(--ink)}
.admin-table tr:last-child td{border-bottom:none}
.admin-table tbody tr:hover{background:rgba(231,154,180,.05)}
.admin-table .actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}
.admin-table form{margin:0}
.badge{background:rgba(201,139,187,.14);color:var(--accent-deep);border:1px solid rgba(201,139,187,.3);font-size:11px;padding:4px 11px;border-radius:999px;text-transform:uppercase;letter-spacing:.06em}
.post-form{background:var(--panel);border:1px solid var(--line-soft);border-radius:20px;padding:30px;max-width:840px;box-shadow:var(--shadow)}
.post-form label{display:block;margin-bottom:18px;font-size:13px;color:var(--muted);font-weight:600}
.post-form .row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px}
.post-form input,.post-form textarea{
  width:100%;margin-top:8px;background:#fbf8fb;border:1px solid var(--line);
  border-radius:12px;color:var(--ink);padding:12px 14px;font-family:var(--sans);font-size:15px;transition:border-color .2s,box-shadow .2s
}
.post-form textarea{resize:vertical;line-height:1.6}
.post-form input:focus,.post-form textarea:focus{outline:none;border-color:var(--rose);box-shadow:0 0 0 3px rgba(231,154,180,.16)}
.post-form .check{display:flex;align-items:center;gap:10px;color:var(--ink)}
.post-form .check input{width:auto;margin:0}
.post-form .opt{color:var(--muted);font-weight:400;font-size:11px;text-transform:none;letter-spacing:0}
.cover-picker{display:flex;flex-wrap:wrap;gap:10px;margin:2px 0 18px}
.cover-opt{width:108px;height:62px;border-radius:12px;border:2px solid var(--line);background-size:cover;background-position:center;cursor:pointer;padding:0;color:var(--muted);font-size:11px;font-family:var(--sans);transition:.2s var(--ease)}
.cover-opt.none{background:#fbf8fb;display:flex;align-items:center;justify-content:center}
.cover-opt:hover{border-color:rgba(201,139,187,.55);transform:translateY(-2px)}
.cover-opt.selected{border-color:var(--rose);box-shadow:0 0 0 3px rgba(231,154,180,.22)}
.flash{padding:13px 17px;border-radius:12px;margin-bottom:22px;font-size:14px}
.flash.ok{background:rgba(166,221,200,.28);border:1px solid rgba(120,190,160,.4);color:#4f8a70}
.flash.error{background:rgba(240,184,205,.3);border:1px solid rgba(199,111,150,.4);color:#a5618f}
.login-page{display:flex;align-items:center;justify-content:center;min-height:100vh}
.login-card{background:var(--panel);border:1px solid var(--line);border-radius:24px;padding:42px;width:min(400px,90vw);text-align:center;box-shadow:var(--shadow)}
.login-card .brand{display:block;margin-bottom:8px}
.login-card .kicker{justify-content:center}
.login-card label{display:block;text-align:left;margin:24px 0 0;font-size:13px;color:var(--muted)}
.login-card input{width:100%;margin-top:8px;background:#fbf8fb;border:1px solid var(--line);border-radius:12px;color:var(--ink);padding:13px;font-size:15px}
.login-card input:focus{outline:none;border-color:var(--rose);box-shadow:0 0 0 3px rgba(231,154,180,.16)}
.login-card button{width:100%;margin-top:24px}
.login-card .hint{color:var(--muted);font-size:12px;margin:18px 0 0}
.login-card code{color:var(--rose-deep);background:#fbf1f6;padding:2px 6px;border-radius:5px}

@media(max-width:920px){
  .hero{grid-template-columns:1fr}
  .grid{grid-template-columns:1fr 1fr}
  .post-form .row{grid-template-columns:1fr}
}
@media(max-width:560px){
  .grid{grid-template-columns:1fr}
  .nav-links{display:none}
}
